fn cleanup_server(endpoint: &str) {
    // Extract port from endpoint
    if let Some(port) = endpoint.rsplit(':').next() {
        let _ = std::process::Command::new("fuser")
            .args(["-k", &format!("{port}/tcp")])
            .output();
    }
}
